## 2. The C / C++ stub (`pcapng_stubs.c`)

> **Important** – this file must be compiled with a C++ compiler (e.g. `g++`)
> because it includes the C++ header of libpcapng.  The `extern "C"` block
> guarantees that the symbols have C linkage so that OCaml can find them.

```c
/* --------------------------------------------------------------
   pcapng_stubs.c – C/C++ glue for the OCaml binding
   -------------------------------------------------------------- */

#define CAML_NAME_SPACE          /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <stddef.h>
#include <stdint.h>
#include <string.h>
#include <stdbool.h>

/* --------------------------------------------------------------
   Minimal C++ wrapper around libpcapng (replace with the real API)
   -------------------------------------------------------------- */
#ifdef __cplusplus
extern "C" {
#endif

/* The real libpcapng header would be something like:
   #include <pcapng.hpp>
   but we only need a tiny façade for the example. */
class PcapngReader {
public:
    explicit PcapngReader(const char* filename);
    ~PcapngReader();

    /* Return true and fill *frame if a frame is available,
       false when the end of file is reached. */
    bool next(struct Frame* frame);
    void close();               /* optional – called from destructor */
};

/* A lightweight C‑compatible description of a frame. */
struct Frame {
    uint64_t ts;       /* nanoseconds since epoch */
    uint32_t len;      /* payload length */
    const uint8_t* data; /* pointer to payload (valid until next call) */
};

#ifdef __cplusplus
}
#endif

/* --------------------------------------------------------------
   OCaml custom operations – we store a pointer to PcapngReader *
   -------------------------------------------------------------- */
static void pcapng_finalize(value v) {
    PcapngReader* r = (PcapngReader*)Data_custom_val(v);
    if (r) {
        delete r;               /* destructor releases all native resources */
    }
}

/* No special comparison needed – we only use the value as a handle. */
static int pcapng_compare(value v1, value v2) {
    PcapngReader* r1 = (PcapngReader*)Data_custom_val(v1);
    PcapngReader* r2 = (PcapngReader*)Data_custom_val(v2);
    if (r1 < r2) return -1;
    if (r1 > r2) return  1;
    return 0;
}

/* The custom operations table */
static struct custom_operations pcapng_ops = {
    "pcapng.iterator",
    pcapng_finalize,
    pcapng_compare,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* --------------------------------------------------------------
   Helper: allocate an OCaml frame record from a native Frame *
   -------------------------------------------------------------- */
static value frame_of_c(const struct Frame* src) {
    CAMLparam0();
    CAMLlocal3(v_ts, v_len, v_data);
    CAMLlocal1(v_rec);

    /* 1. timestamp – OCaml int64 (raw 63‑bit signed, but we treat as unsigned) */
    v_ts = caml_copy_int64((int64_t)src->ts);

    /* 2. length – plain OCaml int (fits in 31/63 bits on all platforms) */
    v_len = Val_int(src->len);

    /* 3. payload – copy into a fresh OCaml bytes value */
    v_data = caml_alloc_string(src->len);
    if (src->len > 0) {
        memcpy(String_val(v_data), src->data, src->len);
    }

    /* 4. Allocate the record { ts; len; data }.
       The order must match the .mli definition. */
    v_rec = caml_alloc_small(3, 0);          /* a block with tag 0 */
    Field(v_rec, 0) = v_ts;
    Field(v_rec, 1) = v_len;
    Field(v_rec, 2) = v_data;

    CAMLreturn(v_rec);
}

/* --------------------------------------------------------------
   OCaml entry points
   -------------------------------------------------------------- */

/* 1. open_file : string -> iterator */
CAMLprim value caml_pcapng_open_file(value v_fname) {
    CAMLparam1(v_fname);
    CAMLlocal1(v_iter);
    const char* fname = String_val(v_fname);
    PcapngReader* r = NULL;

    /* The constructor may throw; we translate that to a Failure exception */
    try {
        r = new PcapngReader(fname);
    } catch (const std::exception& e) {
        caml_failwith(e.what());
    } catch (...) {
        caml_failwith("pcapng: unknown error while opening file");
    }

    /* Allocate the abstract custom block */
    v_iter = caml_alloc_custom(&pcapng_ops, sizeof(PcapngReader*), 0, 1);
    Data_custom_val(v_iter) = (char*)r;   /* store the pointer */
    CAMLreturn(v_iter);
}

/* 2. close : iterator -> unit */
CAMLprim value caml_pcapng_close(value v_iter) {
    CAMLparam1(v_iter);
    PcapngReader* r = (PcapngReader*)Data_custom_val(v_iter);
    if (r) {
        delete r;                 /* destructor does the real close */
        Data_custom_val(v_iter) = (char*)NULL;
    }
    CAMLreturn(Val_unit);
}

/* 3. iter_frames : iterator -> (frame -> unit) -> unit */
CAMLprim value caml_pcapng_iter_frames(value v_iter, value v_cb) {
    CAMLparam2(v_iter, v_cb);
    CAMLlocal1(v_frame);
    PcapngReader* r = (PcapngReader*)Data_custom_val(v_iter);
    struct Frame cframe;
    intnat exception_tag = 0;          /* 0 = no exception, else -> raise */

    if (!r) caml_failwith("pcapng: iterator is already closed");

    /* Walk the native iterator.  We release the OCaml runtime while we are
       inside the C++ loop so that the GC cannot pre‑empt us.  The callback
       re‑acquires the runtime for each call. */
    caml_release_runtime_system();    /* --- start of non‑OCaml region --- */
    while (r->next(&cframe)) {
        /* Convert the C frame into an OCaml value (this copies the payload). */
        v_frame = frame_of_c(&cframe);

        /* Re‑enter OCaml to invoke the user callback. */
        caml_acquire_runtime_system();   /* --- back to OCaml region --- */
        /* The callback may raise; we catch it via caml_callback_exn. */
        value result = caml_callback_exn(v_cb, v_frame);
        if (Is_exception_result(result)) {
            /* Propagate the exception after cleaning up the native iterator. */
            exception_tag = result;
            caml_release_runtime_system();   /* leave C++ world */
            break;
        }
        caml_release_runtime_system();   /* back to native loop */
    }
    caml_release_runtime_system();    /* make sure we are out of OCaml */

    /* If the loop exited because of an exception, re‑raise it now. */
    if (exception_tag != 0) {
        caml_raise(exception_tag);
    }

    CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------
   Registration – the OCaml side will use Dynlink or ocamlc -cclib
   -------------------------------------------------------------- */
#if defined(__unix__) || defined(__APPLE__)
__attribute__((visibility("default")))
#endif
CAMLprim value caml_pcapng_version(value unit) {
    CAMLparam1(unit);
    CAMLreturn(caml_copy_string("pcapng‑OCaml‑binding 1.0"));
}
```

